module top_module(
  input [7:0] XOR_A,
  input [7:0] B,
  output reg [7:0] C
);always @(*) begin
    C[0] = XOR_A[0] ^ B[0];
    C[1] = XOR_A[1] ^ B[1];
    C[2] = XOR_A[2] ^ B[2];
    C[3] = XOR_A[3] ^ B[3];
    C[4] = XOR_A[4] ^ B[4];
    C[5] = XOR_A[5] ^ B[5];
    C[6] = XOR_A[6] ^ B[6];
    C[7] = XOR_A[7] ^ B[7];
  end

endmodule
